module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const use12 = (String(args.format).toLowerCase().replace('h', '') === '12');
const showSec = !(String(args.seconds).toLowerCase() === 'false' || String(args.seconds) === '0');
const sizes = { sm: 'sm', md: 'md', lg: 'lg', xl: 'xl' };
const size = sizes[(args.size || 'md').toLowerCase()] || 'md';
// Appearance: shape (corner style / no box), background, border, text colour,
// digit weight. Each is optional — omitted args fall back to stylesheet defaults.
const shape = String(args.shape || 'rounded').toLowerCase();
const weights = { normal: '400', medium: '600', bold: '700' };
const weight = weights[String(args.weight || 'bold').toLowerCase()] || '700';
const st = [];
st.push('--clock-weight:' + weight);
if (args.bg) st.push('background:' + args.bg);
else if (shape === 'none') st.push('background:transparent');
if (args.border) st.push('border:1.5px solid ' + args.border);
if (args.color) st.push('color:' + args.color);
const radius = shape === 'pill' ? '999px' : (shape === 'square' || shape === 'none') ? '0' : '0.5em';
st.push('border-radius:' + radius);
if (shape === 'none') st.push('padding:0');
const styleAttr = ' style="' + st.join(';') + '"';
// Optional caption before the readout.
const label = String(args.label || '').trim();
const labelHtml = label ? '<span class="mdp-clock-label">' + esc(label) + '</span>' : '';
// Fixed digit width: HH:MM:SS (8) or HH:MM (5). AM/PM lives in its own span.
const chars = showSec ? 8 : 5;
// Static zero placeholder keeps the width correct before the script paints
// (it repaints immediately on init, so this is never actually visible).
const placeholder = showSec ? '00:00:00' : '00:00';
return '<span class="mdp-mod-clock mdp-interactive mdp-size-' + size + '"' + styleAttr
  + ' data-format="' + (use12 ? '12' : '24') + '" data-seconds="' + (showSec ? '1' : '0') + '">'
  + labelHtml
  + '<span class="mdp-clock-time" style="width:' + chars + 'ch">' + placeholder + '</span>'
  + (use12 ? '<span class="mdp-clock-ampm">&nbsp;</span>' : '')
  + '</span>';

module.script:
export default {
  init(el, ctx) {
    const timeEl = el.querySelector('.mdp-clock-time');
    const ampmEl = el.querySelector('.mdp-clock-ampm');
    const use12 = el.dataset.format === '12';
    const showSec = el.dataset.seconds === '1';
    const pad = function (n) { return String(n).padStart(2, '0'); };

    const paint = function () {
      const now = new Date();
      let h = now.getHours();
      let ampm = '';
      if (use12) {
        ampm = h < 12 ? 'AM' : 'PM';
        h = h % 12;
        if (h === 0) h = 12;
      }
      let out = pad(h) + ':' + pad(now.getMinutes());
      if (showSec) out += ':' + pad(now.getSeconds());
      timeEl.textContent = out;
      if (ampmEl) ampmEl.textContent = ampm;
    };

    paint();
    const id = setInterval(paint, 1000);
    ctx.onCleanup(function () { clearInterval(id); });
  }
}
